"""Circle packing: 26 circles, multi-lattice (hex6 + hex5) init + SLSQP for sum of radii."""
import numpy as np
from scipy.optimize import minimize


def construct_packing():
    n = 26
    sqrt3 = np.sqrt(3.0)
    r_max = 1.0 / (2.0 + 5.0 * sqrt3)

    def hex6(transpose=False, flip=False):
        centers = []
        for i in range(6):
            if (i % 2 == 0) ^ flip:
                xs = [r_max + j * 2.0 * r_max for j in range(5)]
            else:
                xs = [2.0 * r_max + j * 2.0 * r_max for j in range(4)]
            y = r_max + i * r_max * sqrt3
            for x in xs:
                centers.append([x, y])
        c = np.array(centers[:n])
        if transpose:
            c = c[:, [1, 0]]
        return c

    def hex5():
        # 5 rows 6/5/6/5/4: binding constraint 2r + 4r*sqrt3 <= 1
        r = 1.0 / (2.0 + 4.0 * sqrt3)
        centers = []
        rows = [6, 5, 6, 5, 4]
        for i, k in enumerate(rows):
            if i % 2 == 0:
                xs = [r + j * 2.0 * r for j in range(k)]
            else:
                xs = [2.0 * r + j * 2.0 * r for j in range(k)]
            y = r + i * r * sqrt3
            for x in xs:
                centers.append([x, y])
        return np.array(centers[:n]), r

    base = hex6()
    radii = np.full(n, r_max)

    def neg_sum(x):
        return -np.sum(x[2*n:])

    def neg_sum_grad(x):
        g = np.zeros_like(x); g[2*n:] = -1.0; return g

    cons = []
    for i in range(n):
        cons.append({'type': 'ineq', 'fun': lambda x, i=i: x[i] - x[2*n + i]})
        cons.append({'type': 'ineq', 'fun': lambda x, i=i: 1.0 - x[i] - x[2*n + i]})
        cons.append({'type': 'ineq', 'fun': lambda x, i=i: x[n+i] - x[2*n + i]})
        cons.append({'type': 'ineq', 'fun': lambda x, i=i: 1.0 - x[n+i] - x[2*n + i]})
    for i in range(n):
        for j in range(i+1, n):
            def pair(x, i=i, j=j):
                dx = x[i] - x[j]; dy = x[n+i] - x[n+j]
                return np.sqrt(dx*dx + dy*dy) - (x[2*n+i] + x[2*n+j])
            cons.append({'type': 'ineq', 'fun': pair})

    bounds = [(0, 1)] * (2*n) + [(1e-6, 0.5)] * n

    def validate_and_shrink(cx, cy, rr):
        rr_s = np.maximum(rr, 0.0) * (1.0 - 1e-7)
        for i in range(n):
            if cx[i] < rr_s[i] or cx[i] > 1 - rr_s[i] or cy[i] < rr_s[i] or cy[i] > 1 - rr_s[i]:
                return None
        for i in range(n):
            for j in range(i+1, n):
                if np.hypot(cx[i]-cx[j], cy[i]-cy[j]) < rr_s[i] + rr_s[j]:
                    return None
        return rr_s

    best_centers = base
    best_radii = np.full(n, r_max * (1.0 - 1e-7))
    best_sum = float(np.sum(best_radii))

    starts = []
    starts.append(np.concatenate([base[:, 0], base[:, 1], radii]))
    c5, r5 = hex5()
    starts.append(np.concatenate([c5[:, 0], c5[:, 1], np.full(n, r5)]))
    starts.append(np.concatenate([c5[:, 1], c5[:, 0], np.full(n, r5)]))

    rng = np.random.default_rng(7)
    for k in range(2):
        pert = rng.normal(scale=0.02, size=(n, 2))
        cx0 = np.clip(base[:, 0] + pert[:, 0], r_max, 1 - r_max)
        cy0 = np.clip(base[:, 1] + pert[:, 1], r_max, 1 - r_max)
        starts.append(np.concatenate([cx0, cy0, radii]))

    for x0 in starts:
        try:
            res = minimize(neg_sum, x0, jac=neg_sum_grad, method='SLSQP',
                           bounds=bounds, constraints=cons,
                           options={'maxiter': 300, 'ftol': 1e-10})
            cx, cy, rr = res.x[:n], res.x[n:2*n], res.x[2*n:]
            rr_s = validate_and_shrink(cx, cy, rr)
            if rr_s is not None:
                s = float(np.sum(rr_s))
                if s > best_sum:
                    best_sum = s
                    best_centers = np.column_stack([cx, cy])
                    best_radii = rr_s
        except Exception:
            pass

    try:
        x0 = np.concatenate([best_centers[:, 0], best_centers[:, 1], best_radii])
        res = minimize(neg_sum, x0, jac=neg_sum_grad, method='SLSQP',
                       bounds=bounds, constraints=cons,
                       options={'maxiter': 500, 'ftol': 1e-12})
        cx, cy, rr = res.x[:n], res.x[n:2*n], res.x[2*n:]
        rr_s = validate_and_shrink(cx, cy, rr)
        if rr_s is not None:
            s = float(np.sum(rr_s))
            if s > best_sum:
                best_sum = s
                best_centers = np.column_stack([cx, cy])
                best_radii = rr_s
    except Exception:
        pass

    return best_centers, best_radii, best_sum
# EVOLVE-BLOCK-END


def run_packing():
    return construct_packing()


if __name__ == "__main__":
    centers, radii, sum_radii = run_packing()
